const R=4*Math.PI*1e-7,S=R/(4*Math.PI);function j(o,u,i,e){let n=0,t=0,a=0;for(const r of e){const{points:c,currentAmps:f,currentDirection:l}=r,m=f*l,p=c.length/3;if(!(p<2))for(let s=0;s<p-1;s++){const g=c[s*3],h=c[s*3+1],B=c[s*3+2],A=c[s*3+3],I=c[s*3+4],_=c[s*3+5],F=(g+A)*.5,E=(h+I)*.5,P=(B+_)*.5,x=o-F,y=u-E,d=i-P,z=x*x+y*y+d*d;if(z<1e-20)continue;const U=z*Math.sqrt(z),b=A-g,w=I-h,D=_-B,V=w*d-D*y,q=D*x-b*d,L=b*y-w*x,M=S*m/U;n+=M*V,t+=M*q,a+=M*L}}return[n,t,a]}function k(o,u){const i=o.length/3,e=new Float32Array(i*3);let n=0;for(let t=0;t<i;t++){const a=o[t*3],r=o[t*3+1],c=o[t*3+2],[f,l,m]=j(a,r,c,u);e[t*3]=f,e[t*3+1]=l,e[t*3+2]=m;const p=Math.sqrt(f*f+l*l+m*m);p>n&&(n=p)}return{fieldVectors:e,maxMagnitude:n}}self.onmessage=o=>{const{coilWirePaths:u,samplePositions:i}=o.data,e=u.map(r=>({points:r.points,currentAmps:r.currentAmps,currentDirection:r.currentDirection})),{fieldVectors:n,maxMagnitude:t}=k(i,e),a={type:"FIELD_RESULT",fieldVectors:n,maxMagnitude:t};self.postMessage(a,{transfer:[n.buffer]})};
